var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"오늘 밤이 괴도가 예고한 날입니다.","JPN":"怪盗が予告していたのは、今夜です。","ENG":"Tonight's the night the phantom thief said she'd steal the painting.","TWN":"今晚就是怪盜所預言的日子。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"언제 어디서 나타날지 모르니 모두 긴장을 풀지 마세요.","JPN":"いつ、どこから現われるかわかりませんので、みんな気を引き締めてください。","ENG":"We don't know when or where she's going to appear, so stay frosty.","TWN":"我們永遠不知道她會在何時何地出現，所以大家不要放鬆。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"로널드 씨. 보안 장치에 신호는 없나요?","JPN":"ロナルド・リーさん。セキュリティー機器に反応はありましたか？","ENG":"Mr. Ronald Lee, any signals on the security device?","TWN":"羅那魯多·李，保全裝置上沒什麼訊號嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"걱정마. 아직 아무것도 안 잡혀.","JPN":"心配するな。まだ何の反応もない。","ENG":"Don't worry. Nothing has been detected yet.","TWN":"不用擔心，目前還沒有任何訊號。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"괴도는 아직인가? 빨리 와주지 않으려나….","JPN":"怪盗はまだか？　早く来てくれないかな……","ENG":"Is the thief not going to show? I hope she comes soon...","TWN":"怪盜還沒來嗎？馬上就要出現了吧…"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"와서 또 햄버거 주면 좋겠다!","JPN":"来て、またハンバーガーくれたらいいね！","ENG":"I hope she brings burgers this time too!","TWN":"這次也會給我漢堡就好了！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"이, 이건 장난이 아닙니다! 조금은 진지하게 임해주세요!","JPN":"こ、これは遊びではありません！　少しは真面目にやってください！","ENG":"Th-this isn't a joke! Please be a little more serious!","TWN":"這、這不是玩笑！請認真一點！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"앗! 불이…?!","JPN":"あっ！　明かりが……！？","ENG":"Huh?! The lights are out...!","TWN":"啊！燈怎麼…？！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"으아아~ 아무것도 안 보여!","JPN":"うああ～何も見えないよ！","ENG":"Aaah...! I can't see a thing!","TWN":"呃啊啊～我什麼也看不見！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"정신없으니까 허둥대지 좀 마!","JPN":"気が散るから、ちょっと落ち着け！","ENG":"Stop frolicking around! It's making me go nuts!","TWN":"煩死了，別手忙腳亂的！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"괴도다운 등장이군! 자 와라!","JPN":"怪盗らしい登場だな！　さあ、来い！","ENG":"What a phantom thief-like entrance! Now, come at me!","TWN":"不愧是怪盜般的登場！儘管來吧！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"위험합니다 아가씨! 어서 대피하셔야 합니다!","JPN":"危険です、お嬢様！　早く退避してください！","ENG":"It's dangerous, Miss Lin! You must get to safety!","TWN":"這很危險，小姐！您必須儘快離開！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"엇, 불이 다시 들어왔어!","JPN":"あっ、また明かりがついたよ！","ENG":"Huh? The lights are back on!","TWN":"呃，燈又亮了！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"그림은 무사한가요?","JPN":"絵は無事ですか？","ENG":"Is the painting safe?","TWN":"畫還在嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"응, 아직 여기 있어!","JPN":"ああ、まだここにある！","ENG":"Yeah, it's still here!","TWN":"是的，還在這裡！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"휴… 전력이 빨리 돌아와서 접근하지 못했나 봐요.","JPN":"ふう……電力が早く復帰して、近づけなかったようですね。","ENG":"Phew... Guess she couldn't get close because the lights came on too quick.","TWN":"呼…看來是因為很快就恢復電了，所以沒能靠近。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"엇, 방금 무언가가…!","JPN":"あっ、今何かが……！","ENG":"Huh? Something just...!","TWN":"呃，剛剛有什麼東西…！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"아하하, 여전히 허둥대느라 바쁘시네요.","JPN":"あはは、相変わらずバタバタと慌ただしいですね。","ENG":"Ah hah hah, I still see you're all running around like headless chickens!","TWN":"哈哈哈，你還是那麼慌慌張張的。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"제가 드린 화장품도 잘 사용하고 계시고, 이거 기쁜걸요?","JPN":"私がプレゼントした化粧品も使ってくれているようで、光栄です。","ENG":"But at least you're using the skincare products I left you. I'm happy for you!","TWN":"喔？看來我給你的化妝品用得很好，這讓我開心呢？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"괴도 J!","JPN":"怪盗J！","ENG":"Phantom Thief J!","TWN":"怪盜J！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"오랜만에 만났는데 그렇게 경계하지 마세요.","JPN":"久しぶりの再会なんです。そう警戒しないでください。","ENG":"Long time no see. But no need to get so defensive now.","TWN":"好久不見了，別那麼緊張嘛。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"혹시라도 넘어지면 아야라도 할까 봐 걱정되잖아요~","JPN":"もし転んでイタイイタイでもしたら大変でしょう？","ENG":"I was worried you might trip and get a boo-boo...!","TWN":"我真擔心會摔疼你呢～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"감히 절 어린이 취급하다니…!","JPN":"私を子ども扱いするなんて……！","ENG":"How dare you treat me like a little child...!","TWN":"你竟敢把我當小朋友…！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};